const purchases = $input.all();

const yahooMap = {
  'APC': 'APC.F', 'AMZ': 'AMZ.F', 'NVD': 'NVD.F', 'AP2': 'AP2.DE', 'MSF': 'MSF.F',
  'TL0': 'TL0.DE', 'TLO': 'TL0.DE', 'TKE': 'TKE.F', 'M4I': 'M4I.F', 'ABEA': 'ABEA.F',
  'CSPX': 'CSPX.AS', 'CNDX': 'CNDX.AS', '3ZU0': '3ZU0.F', '1170': '1170.F',
  '9D5': '9D5.F', 'GXG': 'GXG.F', 'BKSY': 'BKSY',
  'GOLD-ETFP': 'GOLD-EUR.PA',
  'AL2SI': 'AL2SI.PA', 'SU': 'SU.PA', 'ESE': 'ESE.PA',
  'EUEA': 'EUEA.AS', 'STEC': 'STEC.AS', 'ALRIB': 'ALRIB.PA',
  'SOI': 'SOI.PA', 'BTC': 'BTC-EUR'
};

const searchOverrides = {
  'CSPX': 'S&P 500',
  'CNDX': 'NASDAQ 100',
  'GOLD-ETFP': 'cours or gold XAU',
  'EUEA': 'MSCI Europe ETF actions',
  'STEC': 'Europe technologie ETF',
  '3ZU0': 'Dow Jones ETF',
  '1170': 'Bitcoin ETF'
};

const netQty = {};
const nameMap = {};
for (const item of purchases) {
    const ticker = (item.json.ticker || '').toUpperCase().trim();
    const qty = parseFloat(item.json.quantity) || 0;
    if (!ticker || ticker.startsWith('CASH-')) continue;
    netQty[ticker] = (netQty[ticker] || 0) + qty;
    if (!nameMap[ticker]) nameMap[ticker] = item.json.name || ticker;
}

const seen = new Set();
const results = [];
for (const [ticker, qty] of Object.entries(netQty)) {
    if (qty < 0.01) continue;
    const yahooTicker = yahooMap[ticker] || ticker;
    if (seen.has(yahooTicker)) continue;
    seen.add(yahooTicker);
    const name = nameMap[ticker] || ticker;
    const searchName = searchOverrides[ticker] || name;
    results.push({ json: { yahooTicker, name, searchName } });
}

return results;

const httpResponses = $input.all();
const tickerItems = $('Build Ticker List').all();

const twentyFourHoursAgo = Math.floor(Date.now() / 1000) - 24 * 3600;
const allNews = [];
const seenUUIDs = new Set();

function getTag(s, tag) {
    const open = '<' + tag;
    const close = '</' + tag + '>';
    const si = s.indexOf(open);
    const ei = s.indexOf(close);
    if (si === -1 || ei === -1) return '';
    const raw = s.substring(s.indexOf('>', si) + 1, ei).trim();
    if (raw.startsWith('<![CDATA[') && raw.endsWith(']]>')) return raw.slice(9, -3).trim();
    return raw;
}

for (let i = 0; i < httpResponses.length; i++) {
    const rawData = httpResponses[i].json;
    const xml = (rawData && typeof rawData.data === 'string') ? rawData.data : '';
    const tickerInfo = tickerItems[i] ? tickerItems[i].json : {};
    const name = tickerInfo.name || tickerInfo.yahooTicker || 'Unknown';
    const yahooTicker = tickerInfo.yahooTicker || name;

    if (!xml) continue;

    const parts = xml.split('<item>');
    for (let j = 1; j < parts.length; j++) {
        const part = parts[j].split('</item>')[0];

        const title = getTag(part, 'title');
        const link = getTag(part, 'link');
        const pubDate = getTag(part, 'pubDate');
        const guid = getTag(part, 'guid') || link || title;
        const publisher = getTag(part, 'source') || 'Google News';

        if (!title || !guid) continue;

        const publishedAt = pubDate ? Math.floor(new Date(pubDate).getTime() / 1000) : 0;
        if (publishedAt < twentyFourHoursAgo) continue;
        if (seenUUIDs.has(guid)) continue;
        seenUUIDs.add(guid);

        allNews.push({ uuid: guid, title, publisher, link, publishedAt, ticker: yahooTicker, name });
    }
}

allNews.sort((a, b) => b.publishedAt - a.publishedAt);

const byAssetCount = {};
const limitedNews = [];
for (const item of allNews) {
    byAssetCount[item.name] = (byAssetCount[item.name] || 0) + 1;
    if (byAssetCount[item.name] <= 3) limitedNews.push(item);
}

return [{ json: { news: limitedNews.slice(0, 30), count: limitedNews.length } }];

const data = $('Collect News').first().json;
const sentDoc = $input.first().json || {};

const sentIds = new Set(sentDoc.ids || []);
const news = data.news || [];

const newItems = news.filter(item => !sentIds.has(item.uuid)).slice(0, 30);

return [{ json: {
    hasNews: newItems.length > 0,
    news: newItems,
    count: newItems.length,
    existingSentIds: sentDoc.ids || []
}}];

const { existingSentIds } = $('Filter Unsent').first().json;
const { selectedUUIDs } = $('Format Message').first().json;
const allSentIds = [...(existingSentIds || []), ...(selectedUUIDs || [])].slice(-500);
return [{ json: { ids: allSentIds } }];

const { news } = $input.first().json;

const newsForGemini = news.map(function(item, idx) {
    return { idx: idx, titre: item.title.substring(0, 150), actif: item.name };
});

const prompt = `Tu es un redacteur financier senior specialise en analyse de portefeuille.

MISSION : Parmi ces actualites financieres, selectionne les 3 a 5 plus importantes pour un investisseur.
Criteres : resultats trimestriels, M&A, mouvements de cours significatifs, annonces strategiques majeures.

REGLES STRICTES :
- Maximum 1 actualite par actif (pas de doublons)
- Ignorer les news anecdotiques sans impact boursier direct
- Pour chaque news retenue : redige une analyse de 4 a 6 phrases en francais :
  * Impact concret sur la position dans le portefeuille
  * Raison principale de ce mouvement ou de cette annonce
  * Contexte de marche et comparaison sectorielle
  * Ce que l'investisseur doit surveiller dans les prochains jours
- Objectif : exploiter les 4000 caracteres disponibles avec des analyses denses et actionnables

FORMAT DE REPONSE : JSON valide uniquement, rien d'autre.
{"selected":[{"idx":0,"impact":"analyse detaillee 4-6 phrases"},{"idx":2,"impact":"analyse detaillee 4-6 phrases"}]}

Actualites a analyser :
` + JSON.stringify(newsForGemini);

return [{ json: { input: prompt, news } }];

const geminiResp = $input.first().json;
const { news } = $('Build Gemini Prompt').first().json;

let selectedNews = [];
try {
    const text = geminiResp.output || geminiResp.text || '';
    const s = text.indexOf('{');
    const e = text.lastIndexOf('}');
    if (s !== -1 && e > s) {
        const parsed = JSON.parse(text.substring(s, e + 1));
        for (const it of (parsed.selected || [])) {
            if (typeof it.idx === 'number' && news[it.idx]) {
                selectedNews.push(Object.assign({}, news[it.idx], { impact: it.impact || '' }));
            }
        }
    }
} catch(err) {}

if (selectedNews.length === 0) selectedNews = news.slice(0, 5);

const seenAssets = new Set();
selectedNews = selectedNews.filter(function(item) {
    if (seenAssets.has(item.name)) return false;
    seenAssets.add(item.name);
    return true;
});

const NL = '\n';
function esc(s) { return (s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); }
function dec(s) { return (s || '').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>'); }

const separator = NL + NL + '-----' + NL + NL;

const blocks = selectedNews.map(function(item) {
    const d = new Date(item.publishedAt * 1000);
    const hh = d.getHours().toString().padStart(2, '0');
    const mm = d.getMinutes().toString().padStart(2, '0');
    const title = esc(dec(item.title));
    let block = '<b>&#128204; ' + esc(item.name) + '</b>' + NL;
    block += '&#128202; ' + title + NL;
    block += '   <i>' + esc(item.publisher) + ' · ' + hh + ':' + mm + '</i>';
    if (item.link) block += ' · <a href="' + item.link + '">Lire</a>';
    if (item.impact) {
        const imp = item.impact.length > 500 ? item.impact.substring(0, 500) + '...' : item.impact;
        block += NL + '   &#128188; <i>' + esc(imp) + '</i>';
    }
    return block;
});

const header = '&#128276; <b>Breaking News Portfolio</b> <i>(' + selectedNews.length + ' actus)</i>';
let message = header;
for (let i = 0; i < blocks.length; i++) {
    const candidate = message + (i === 0 ? NL + NL : separator) + blocks[i];
    if (candidate.length > 4090) break;
    message = candidate;
}
const selectedUUIDs = selectedNews.map(function(item) { return item.uuid; });

return [{ json: { chatId: '2089017736', message, selectedUUIDs } }];
